    PASS condition: dangerous HTML tags are escaped (< becomes &lt;)
    FAIL condition: unescaped HTML tags with script/event handlers
    """
    import re

    payloads = [
        "<script>alert('XSS')</script>",
        "<img onerror='alert(1)' src=x>",
        "<svg onload='alert(1)'>",
        "javascript:alert(1)",
    ]

